import { GoogleGenAI, Type } from "@google/genai";
import { Contributor, Transaction } from '../types';
import { Logger } from "./monitoringService";

const getAIClient = () => {
    if (!process.env.API_KEY) {
        console.error("CRITICAL: Gemini API Key is missing.");
        throw new Error("Chave de API do Gemini não configurada.");
    }
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

/**
 * 🛡️ JSON SHIELD (V14): Sanitiza, repara e valida a saída da IA com foco em blocos lógicos.
 */
const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    if (typeof input === 'object' && !Array.isArray(input)) {
        return input.rows || input.transactions || input;
    }

    let sanitized = String(input).trim();
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    try {
        const parsed = JSON.parse(sanitized);
        return parsed.rows || parsed.transactions || parsed;
    } catch (e) {
        console.warn("[IA:REPAIR] Tentando reparar JSON...");
        if (sanitized.includes('"rows": [')) {
            let repaired = sanitized;
            if (!repaired.endsWith(']')) repaired += ']';
            if (!repaired.endsWith('}')) repaired += '}';
            try { return JSON.parse(repaired).rows; } catch (inner) {}
        }
        return fallback;
    }
};

async function callWithSimpleRetry(fn: () => Promise<any>, retries = 2): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        if (retries > 0) {
            console.log(`[IA:RETRY] Falha na chamada, tentando novamente... (${retries} restantes)`);
            await new Promise(r => setTimeout(r, 2000));
            return callWithSimpleRetry(fn, retries - 1);
        }
        throw error;
    }
};

export const extractTransactionsWithModel = async (rawText: string, modelContext?: string): Promise<any> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();

        const referencePrompt = modelContext 
            ? `SUA TAREFA É EXTRAIR TRANSAÇÕES SEGUINDO ESTE GABARITO ESTRUTURAL:
               --- INÍCIO DO GABARITO ---
               ${modelContext}
               --- FIM DO GABARITO ---

               REGRAS CRÍTICAS DE FIDELIDADE:
               1. EXTRAÇÃO MULTI-LINHA: Frequentemente, os dados de uma única transação estão espalhados por várias linhas consecutivas (ex: Linha 1 tem data/valor, Linha 3 tem o Nome, Linha 5 tem a Forma de Pagamento). Agrupe-os conforme o exemplo do usuário.
               2. DESCRIÇÃO LIMPA: Retorne exatamente o nome e informações identificadoras conforme o padrão ensinado.
               3. VALORES: Débitos devem ser NEGATIVOS.`
            : "Extraia transações deste extrato. Atenção a dados espalhados em múltiplas linhas para uma mesma transação. Débitos = Negativos.";

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `${referencePrompt}

            TEXTO PARA PROCESSAR:
            ${rawText.substring(0, 18000)}`,
            config: {
                temperature: 0,
                thinkingConfig: { thinkingBudget: 0 },
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rows: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    date: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    amount: { type: Type.NUMBER },
                                    type: { type: Type.STRING },
                                    paymentMethod: { type: Type.STRING }
                                },
                                required: ["date", "description", "amount"]
                            }
                        }
                    }
                }
            }
        });

        return safeJsonParse(response.text, { rows: [] });
    });
};

