import { useState, useCallback } from 'react';
import { extractStructuredDataByExample } from '../services/geminiService';
import { FileModel, Transaction } from '../types';

export interface LearningPackage {
    model: Partial<FileModel>;
    sampleTransactions: Transaction[];
    confidence: number;
}

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any, context?: string[][] } | null>(null);

    /**
     * APLICAR PADRÃO (V19 - CONTEXTUAL MULTI-LINHA):
     * Otimizado para capturar relações entre linhas diferentes conforme a foto enviada.
     */
    const handleApplyCorrectionPattern = useCallback(async (): Promise<LearningPackage | null> => {
        if (!learnedPatternSource || gridData.length === 0) return null;

        setIsInferringMapping(true);

        try {
            const { originalRaw, corrected } = learnedPatternSource;

            // Enviamos 80 linhas para que a IA tenha contexto suficiente de blocos repetidos
            const rawSnippet = gridData.slice(0, 80).map(row => row.join(';')).join('\n');

            const userExample = `O usuário realizou uma correção manual profunda para te ensinar a extrair blocos lógicos deste banco.

               REGRA DE OURO (COMPARE O BLOCO E APRENDA):
               - CONTEXTO ORIGINAL (O que a IA viu): [${originalRaw.join(' | ')}]
               - RESULTADO DESEJADO PELO USUÁRIO (A Meta):
                 * Data: "${corrected.date}"
                 * Descrição Limpa: "${corrected.cleanedDescription}"
                 * Valor: "${corrected.amount}"
                 * Forma: "${corrected.paymentMethod}"

               TAREFA DE APRENDIZADO:
               1. Note que o usuário pode ter buscado o Nome ou a Forma em linhas DIFERENTES da linha que contém a Data/Valor.
               2. Identifique o deslocamento (offset) de linhas. Ex: "O nome está 2 linhas abaixo da data".
               3. Aplique essa lógica de 'montagem de quebra-cabeça' em todo o documento.
               4. Ignore linhas de rodapé, cabeçalho e saldos que não se encaixam neste bloco.
               5. Retorne o resultado como um array JSON 'rows' de transações consolidadas.`;

            const result = await extractStructuredDataByExample(rawSnippet, userExample);

            if (result && result.rows && result.rows.length > 0) {
                console.log(`[Learn:AI] Sucesso! Padrão Multi-linha aplicado em ${result.rows.length} transações.`);

                const reStructuredGrid = result.rows.map((r: any) => [
                    String(r.date || ''), 
                    String(r.description || ''), 
                    String(r.amount || '0'),
                    String(r.type || 'AUTO'),
                    String(r.paymentMethod || 'OUTROS')
                ]);

                setGridData(reStructuredGrid);

                const mapping = { 
                    dateColumnIndex: 0, 
                    descriptionColumnIndex: 1, 
                    amountColumnIndex: 2, 
                    typeColumnIndex: 3,
                    paymentMethodColumnIndex: 4,
                    extractionMode: 'COLUMNS' as const,
                    skipRowsStart: 0,
                    skipRowsEnd: 0,
                    decimalSeparator: '.' as const,
                    thousandsSeparator: '' as const
                };

                setActiveMapping(mapping);
                showToast("Padrão multi-linha aprendido e aplicado com sucesso!", "success");
                setLearnedPatternSource(null); 

                return {
                    model: { mapping },
                    sampleTransactions: [], 
                    confidence: 1.0
                };
            }

            showToast("Não foi possível identificar a relação entre as linhas. Tente outra correção mais explícita.", "error");
            return null;

        } catch (e: any) { 
            console.error("[Learn:FAIL]", e);
            showToast("Erro ao processar aprendizado contextual.", "error"); 
            return null;
        } finally { 
            setIsInferringMapping(false); 
        }
    }, [learnedPatternSource, gridData, setGridData, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};

import React from 'react';
import { PencilIcon, CheckCircleIcon, XMarkIcon, DocumentArrowDownIcon, SparklesIcon } from '../../Icons';

interface SimulatedResultsTableProps {
    transactions: any[];
    activeMapping: boolean;
    isTestMode: boolean;
    editingRowIndex: number | null;
    editingRowData: any | null;
    onStartEdit: (tx: any, idx: number) => void;
    onSaveRow: () => void;
    onCancelEdit: () => void;
    onUpdateEditingData: (data: any) => void;
}

const formatToBRL = (val: string | number) => {
    const num = typeof val === 'string' ? parseFloat(val) : val;
    if (isNaN(num)) return 'R$ 0,00';
    return num.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
};

export const SimulatedResultsTable: React.FC<SimulatedResultsTableProps> = ({
    transactions,
    activeMapping,
    isTestMode,
    editingRowIndex,
    editingRowData,
    onStartEdit,
    onSaveRow,
    onCancelEdit,
    onUpdateEditingData
}) => {
    if (transactions.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center bg-white dark:bg-[#0F172A]">
                <div className="relative mb-4">
                    <div className="absolute inset-0 bg-brand-blue blur-xl opacity-20 animate-pulse rounded-full"></div>
                    <SparklesIcon className="w-12 h-12 text-brand-blue relative z-10 animate-bounce" />
                </div>
                <h5 className="text-sm font-bold text-slate-800 dark:text-white uppercase tracking-widest mb-2">IA Analisando Documento</h5>
                <p className="text-xs text-slate-500 dark:text-slate-400 max-w-xs mx-auto leading-relaxed">
                    Estamos identificando padrões e agrupando linhas para entregar o resultado 100% fiel ao modelo original.
                </p>
            </div>
        );
    }

    return (
        <table className="w-full text-xs text-left border-collapse">
            <thead className="sticky top-0 bg-white dark:bg-slate-900 z-10 border-b border-slate-200 dark:border-slate-700 shadow-sm">
                <tr>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400 w-24 uppercase tracking-tighter">Data</th>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400 uppercase tracking-tighter">Descrição (Limpa)</th>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400 w-24 uppercase tracking-tighter">Tipo</th>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400 w-24 uppercase tracking-tighter">Forma</th>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400 text-right w-28 uppercase tracking-tighter">Valor</th>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400 text-center w-16 uppercase tracking-tighter">Ação</th>
                </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800/50">
                {transactions.map((tx, idx) => {
                    const isEditing = editingRowIndex === idx;
                    const isPending = tx.status === 'pending';
                    const isInvalid = !tx.isValid && tx.status === 'error'; 
                    const isIgnored = tx.status === 'ignored';

                    if (isEditing && editingRowData) {
                        return (
