import { GoogleGenAI, Type } from "@google/genai";
import { Transaction } from '../types';
import { Logger } from "./monitoringService";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("Chave de API do Gemini não configurada.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

/**
 * 🛡️ JSON SHIELD (V16): Extração robusta de blocos complexos.
 */
const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    let sanitized = String(input).trim();
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    try {
        const parsed = JSON.parse(sanitized);
        return parsed.rows || parsed.transactions || (Array.isArray(parsed) ? parsed : fallback);
    } catch (e) {
        console.warn("[IA:REPAIR] Falha no parse, tentando extração de emergência...");
        const arrayMatch = sanitized.match(/\[\s*\{.*\}\s*\]/s);
        if (arrayMatch) {
            try { return JSON.parse(arrayMatch[0]); } catch (inner) {}
        }
        return fallback;
    }
};

async function callWithSimpleRetry(fn: () => Promise<any>, retries = 2): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        if (retries > 0) {
            await new Promise(r => setTimeout(r, 2000));
            return callWithSimpleRetry(fn, retries - 1);
        }
        throw error;
    }
};

/**
 * MOTOR DE EXTRAÇÃO DE BLOCO (SICOOB/MULTI-LINHA)
 * Este motor não usa colunas, ele usa análise de vizinhança textual.
 */
export const extractTransactionsFromComplexBlock = async (rawText: string): Promise<any> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `AJA COMO UM EXTRATOR FINANCEIRO DE PRECISÃO ABSOLUTA.
            O documento fornecido é um extrato bancário (ex: Sicoob) onde cada transação ocupa VÁRIAS LINHAS.

            REGRAS DE EXTRAÇÃO:
            1. IDENTIFICAÇÃO DE BLOCO: Uma transação começa com uma Data (DD/MM ou DD/MM/AAAA) e um Valor (ex: 1.500,00C).
            2. CAPTURA DE NOME: O nome do pagador/beneficiário (ex: Elisabeth Rosa...) geralmente está 2 ou 3 linhas ABAIXO da linha de data/valor. 
            3. CAPTURA DE FORMA: A forma de pagamento (ex: DOC.: Pix) está logo abaixo do nome.
            4. CONSOLIDAÇÃO: Você deve unir essas 5 ou 6 linhas em um ÚNICO objeto JSON.
            5. FIDELIDADE: Não altere o nome. Copie exatamente como está no texto.
            6. SINAIS: Valores com 'D' ou sinal de menos são NEGATIVOS. Valores com 'C' ou sem sinal são POSITIVOS.

            TEXTO BRUTO PARA ANALISAR:
            ${rawText.substring(0, 25000)}`,
            config: {
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rows: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    date: { type: Type.STRING },
                                    description: { type: Type.STRING, description: "Nome completo do pagador extraído das linhas abaixo" },
                                    amount: { type: Type.NUMBER },
                                    type: { type: Type.STRING, description: "ENTRADA ou SAÍDA" },
                                    paymentMethod: { type: Type.STRING, description: "Ex: Pix, TED, DOC" }
                                },
                                required: ["date", "description", "amount"]
                            }
                        }
                    }
                }
            }
        });

        const data = safeJsonParse(response.text);
        return data;
    });
};

export const extractTransactionsWithModel = async (rawText: string, modelContext?: string): Promise<any> => {
    // Se for modo bloco ou documento complexo, usa o motor de bloco
    if (modelContext?.includes('BLOCK') || rawText.length > 1000) {
        return extractTransactionsFromComplexBlock(rawText);
    }

    // Fallback para modelos simples de coluna
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Extraia transações seguindo este gabarito: ${modelContext}\n\nTexto:\n${rawText.substring(0, 15000)}`,
            config: {
                temperature: 0,
                responseMimeType: "application/json"
            }
        });
        return safeJsonParse(response.text);
    });
};

