/**
 * 🎛️ INGESTION ORCHESTRATOR (V12 - PRESERVAÇÃO INTEGRAL)
 * -------------------------------------------------------
 * Para garantir 100% de fidelidade em modelos multi-linha (Sicoob/Inter),
 * NÃO podemos inserir delimitadores artificiais (;) que quebrem a estrutura visual.
 */
export const IngestionOrchestrator = {
    /**
     * Normalização: Apenas limpa espaços vazios e garante quebras de linha padrão.
     * Mantém o layout visual para a IA.
     */
    normalizeRawContent(content: string): string {
        if (!content) return "";

        // Se já é CSV (tem ponto e vírgula), mantemos.
        if (content.includes(';')) return content;

        // Se é texto puro de PDF/TXT, mantemos o layout visual.
        // A IA é mais inteligente que um split('  ') para achar o nome em blocos.
        return content
            .split(/\r?\n/)
            .map(line => line.trimEnd())
            .filter(l => l.trim().length > 0)
            .join('\n');
    },

    async processFile(
        file: File, 
        content: string, 
        models: FileModel[], 
        globalKeywords: string[]
    ): Promise<any> {
        const fileNameLower = file.name.toLowerCase();
        const isExcel = fileNameLower.endsWith('.xlsx') || fileNameLower.endsWith('.xls');

        // NORMALIZAÇÃO: Preserva o layout visual original
        const processedContent = isExcel ? content : this.normalizeRawContent(content);

        const fingerprint = Fingerprinter.generate(processedContent);

        console.log(`[Pipeline:INGESTION] Processando: ${file.name} | Modo: ${isExcel ? 'Excel' : 'Layout Visual'}`);

        const result = await StrategyEngine.process(
            file.name, 
            { __rawText: processedContent, __source: 'file' }, 
            models, 
            globalKeywords
        );

        return {
            source: 'upload',
            transactions: result.transactions || [],
            status: result.status,
            fileName: result.fileName || file.name,
            fingerprint: result.fingerprint || fingerprint || { columnCount: 0 },
            preview: result.preview || processedContent.substring(0, 500),
            strategyUsed: result.strategyName
        };
    },

    async processVirtualData(
        sourceName: string,
        transactions: Transaction[],
        globalKeywords: string[]
    ): Promise<any> {
        return {
            source: 'virtual',
            transactions: transactions,
            strategyUsed: `Virtual:${sourceName}`,
            fingerprint: { columnCount: 3 }
        };
    }
};

import { useState, useCallback, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { TypeResolver } from '../core/processors/TypeResolver';
import { extractTransactionsFromComplexBlock } from '../services/geminiService';

interface SafeTransaction extends Transaction {
    sourceIndex?: number;
    isValid?: boolean;
    status?: 'valid' | 'error' | 'edited' | 'ignored' | 'pending';
}

interface UseSimulationProps {
    gridData: string[][];
    activeMapping: any;
    cleaningKeywords: string[];
}

export const useSimulation = ({ gridData, activeMapping, cleaningKeywords }: UseSimulationProps) => {
    const [processedTransactions, setProcessedTransactions] = useState<SafeTransaction[]>([]);
    const [editingRowIndex, setEditingRowIndex] = useState<number | null>(null);
    const [editingRowData, setEditingRowData] = useState<SafeTransaction | null>(null);
    const [isSimulating, setIsSimulating] = useState(false);

    const lastDataRef = useRef<string>('');
    const lastMappingRef = useRef<string>('');

    const runSimulation = useCallback(async () => {
        if (!gridData || gridData.length === 0) {
            setProcessedTransactions([]);
            return;
        }

        const mapping = activeMapping || { extractionMode: 'BLOCK' };
        setIsSimulating(true);

        try {
            // MODO BLOCO OU IA (Sicoob/Inter): Extração Cognitiva é Obrigatória
            // Se as colunas não estão configuradas ou o modo é bloco, usamos a IA
            const isManualMappingComplete = mapping.dateColumnIndex >= 0 && mapping.amountColumnIndex >= 0;

            if (mapping.extractionMode === 'BLOCK' || !isManualMappingComplete) {
                // Enviamos o texto bruto consolidado para a IA
                const rawText = gridData.map(row => row.join(' ')).join('\n');
                const aiResult = await extractTransactionsFromComplexBlock(rawText);

                if (aiResult && aiResult.length > 0) {
                    setProcessedTransactions(aiResult.map((tx: any, i: number) => ({
                        ...tx,
                        id: `block-tx-${i}-${Date.now()}`,
                        rawDescription: tx.description,
                        cleanedDescription: tx.description,
                        originalAmount: String(tx.amount),
                        contributionType: tx.type || 'AUTO',
                        paymentMethod: tx.paymentMethod || 'OUTROS',
                        isValid: true,
                        status: 'valid' as const
                    })));
                } else {
                    setProcessedTransactions([]);
                }
            } 
            // MODO COLUNAS (Excel/CSV Simples): Lógica Determinística
            else {
                const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, paymentMethodColumnIndex, skipRowsStart } = mapping;
                const newTransactions: SafeTransaction[] = [];
                const yearAnchor = DateResolver.discoverAnchorYear(gridData);

                gridData.forEach((cols, index) => {
                    const isSkipped = index < (skipRowsStart || 0);
                    const rawDate = cols[dateColumnIndex] || '';
                    const rawDesc = cols[descriptionColumnIndex] || '';
                    const rawAmount = cols[amountColumnIndex] || '';

                    if (!rawDate && !rawDesc && !rawAmount) return;

                    const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
                    const amountStr = AmountResolver.clean(rawAmount);
                    const amountValue = parseFloat(amountStr);

                    newTransactions.push({ 
                        id: `sim-${index}-${Date.now()}`,
                        date: isoDate || rawDate || "---", 
                        description: rawDesc || "---", 
                        rawDescription: rawDesc || "---", 
                        paymentMethod: (paymentMethodColumnIndex !== undefined && cols[paymentMethodColumnIndex]) ? cols[paymentMethodColumnIndex] : TypeResolver.resolveFromDescription(rawDesc),
                        amount: isNaN(amountValue) ? 0 : amountValue, 
                        originalAmount: rawAmount, 
                        cleanedDescription: rawDesc, 
                        contributionType: 'AUTO', 
                        sourceIndex: index, 
                        isValid: !!isoDate && !isNaN(amountValue), 
                        status: isSkipped ? 'ignored' : 'valid'
                    });
                });
                setProcessedTransactions(newTransactions);
            }
        } catch (e) {
            console.error("Extraction error:", e);
        } finally {
            setIsSimulating(false);
        }
    }, [gridData, activeMapping]);

    useEffect(() => {
        const dataHash = gridData.length > 0 ? `${gridData.length}-${gridData[0].join('|').substring(0, 50)}` : 'empty';
        const mappingKey = JSON.stringify(activeMapping);
        if (dataHash !== lastDataRef.current || mappingKey !== lastMappingRef.current) {
            lastDataRef.current = dataHash;
            lastMappingRef.current = mappingKey;
            runSimulation();
        }
    }, [gridData, activeMapping, runSimulation]);

    return {
        processedTransactions,
        isSimulating,
        runSimulation,
        editingRowIndex,
        editingRowData,
        setEditingRowData,
        startEdit: (tx: any, idx: number) => { 
            setEditingRowIndex(idx); 
            setEditingRowData({ ...tx }); 
        },
        saveRow: (onLearned?: any) => {
            if (editingRowIndex !== null && editingRowData) {
                const updatedTx = { ...editingRowData, status: 'edited' as const, isValid: true };
                setProcessedTransactions(prev => { const n = [...prev]; n[editingRowIndex] = updatedTx; return n; });
                if (onLearned && editingRowData.sourceIndex !== undefined) onLearned(gridData[editingRowData.sourceIndex], updatedTx);
                setEditingRowIndex(null);
            }
        },
        cancelEdit: () => setEditingRowIndex(null)
    };
};

