import { GoogleGenAI, Type } from "@google/genai";
import { Transaction } from '../types';
import { Logger } from "./monitoringService";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("Chave de API do Gemini não configurada.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    let sanitized = String(input).trim();
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    try {
        const parsed = JSON.parse(sanitized);
        return parsed.rows || parsed.transactions || (Array.isArray(parsed) ? parsed : fallback);
    } catch (e) {
        const arrayMatch = sanitized.match(/\[\s*\{.*\}\s*\]/s);
        if (arrayMatch) {
            try { return JSON.parse(arrayMatch[0]); } catch (inner) {}
        }
        return fallback;
    }
};

async function callWithSimpleRetry(fn: () => Promise<any>, retries = 2): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        if (retries > 0) {
            await new Promise(r => setTimeout(r, 2000));
            return callWithSimpleRetry(fn, retries - 1);
        }
        throw error;
    }
};

/**
 * MOTOR DE EXTRAÇÃO NEUTRO (V17)
 * Removidas referências a bancos específicos para respeitar a exclusão de modelos do usuário.
 */
export const extractTransactionsFromComplexBlock = async (rawText: string, instruction?: string): Promise<any> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();

        const basePrompt = instruction 
            ? `TREINE O SEGUINTE PADRÃO DETERMINÍSTICO:
               ${instruction}

               Aplique este padrão rigorosamente em todo o texto abaixo.`
            : `Extraia transações financeiras deste texto. 
               Se não houver um padrão claro de bloco ensinado, extraia apenas dados explícitos de cada linha de forma individual.
               Não tente agrupar linhas a menos que o usuário tenha fornecido um GABARITO.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `${basePrompt}

            TEXTO PARA ANALISAR:
            ${rawText.substring(0, 25000)}`,
            config: {
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rows: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    date: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    amount: { type: Type.NUMBER },
                                    type: { type: Type.STRING },
                                    paymentMethod: { type: Type.STRING }
                                },
                                required: ["date", "description", "amount"]
                            }
                        }
                    }
                }
            }
        });

        return safeJsonParse(response.text);
    });
};

export const extractTransactionsWithModel = async (rawText: string, modelContext?: string): Promise<any> => {
    // Se não há contexto de modelo, não aplicamos inteligência "hallucinada"
    if (!modelContext) {
