    }

    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `EXTRAÇÃO SOB CONTRATO (FIDELIDADE 100%):
            Use este gabarito ensinado pelo usuário:
            ${modelContext}

            TEXTO:
            ${rawText.substring(0, 20000)}`,
            config: {
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rows: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    date: { type: Type.STRING },
