import { useState, useCallback } from 'react';
import { extractStructuredDataByExample } from '../services/geminiService';
import { FileModel, Transaction } from '../types';

export interface LearningPackage {
    model: Partial<FileModel>;
    sampleTransactions: Transaction[];
    confidence: number;
}

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any, context?: string[][] } | null>(null);

    /**
     * APLICAR PADRÃO (V22 - DESCOBERTA SEMÂNTICA):
     * Ensina a IA a descobrir a relação entre o que o usuário digitou e o texto bruto.
     */
    const handleApplyCorrectionPattern = useCallback(async (): Promise<LearningPackage | null> => {
        if (!learnedPatternSource || gridData.length === 0) return null;

        setIsInferringMapping(true);

        try {
            const { originalRaw, corrected } = learnedPatternSource;

            // Amostra do documento para a IA entender o contexto
            const rawSnippet = gridData.slice(0, 100).map((row, i) => `L${i}: ${row.join(' ; ')}`).join('\n');

            const userExample = `O usuário realizou uma correção manual para te ensinar a lógica de extração deste arquivo específico.

               DADO BRUTO ANALISADO: 
               "${originalRaw.join(' | ')}"

               O QUE O USUÁRIO QUER (MODELO DE SUCESSO):
               - Data Final: "${corrected.date}"
               - Nome/Descrição Limpa: "${corrected.cleanedDescription}"
               - Valor Final: "${corrected.amount}"
               - Forma de Pagamento: "${corrected.paymentMethod}"

               TAREFA DE APRENDIZADO:
               1. ANALISE: Onde o usuário encontrou o nome "${corrected.cleanedDescription}"? Estava dentro de uma string maior (ex: "RECEBIMENTO PIX..."), em outra coluna ou em uma linha vizinha?
               2. ANALISE: De onde veio o valor "${corrected.amount}"? 
               3. ANALISE: Como a data "${corrected.date}" foi formada?
               4. REGRAS: Crie uma regra interna que limpe as descrições (removendo códigos, CPF, nomes de banco) para retornar APENAS o nome do pagador conforme o exemplo.
               5. GENERALIZE: Aplique essa mesma lógica de limpeza e posicionamento para identificar TODAS as transações similares no texto abaixo.
               6. RESULTADO: Retorne o array 'rows' com os dados extraídos seguindo fielmente este novo padrão de limpeza e organização.`;

            const result = await extractStructuredDataByExample(rawSnippet, userExample);

            if (result && result.rows && result.rows.length > 0) {
                console.log(`[IA:PATTERN_LEARN] Padrão aprendido e aplicado em ${result.rows.length} itens.`);

                const reStructuredGrid = result.rows.map((r: any) => [
                    String(r.date || ''), 
                    String(r.description || ''), 
                    String(r.amount || '0'),
                    String(r.type || 'AUTO'),
                    String(r.paymentMethod || 'OUTROS')
                ]);

                setGridData(reStructuredGrid);

                // Salva o estado de extração
                const mapping = { 
                    extractionMode: 'BLOCK' as const, // Modo Bloco força a IA a usar o aprendizado cognitivo
                    dateColumnIndex: 0, 
                    descriptionColumnIndex: 1, 
                    amountColumnIndex: 2, 
                    typeColumnIndex: 3,
                    paymentMethodColumnIndex: 4,
                    skipRowsStart: 0,
                    skipRowsEnd: 0,
                    decimalSeparator: '.' as const,
                    thousandsSeparator: '' as const
                };

                setActiveMapping(mapping);
                showToast("Padrão aprendido e aplicado com 100% de fidelidade!", "success");
                setLearnedPatternSource(null); 

                return {
                    model: { mapping },
                    sampleTransactions: [], 
                    confidence: 1.0
                };
            }

            showToast("Não consegui identificar a lógica desta correção. Tente ajustar o nome de forma mais clara.", "error");
            return null;

        } catch (e: any) { 
            console.error("[IA:FAIL]", e);
            showToast("Erro ao processar aprendizado dinâmico.", "error"); 
            return null;
        } finally { 
            setIsInferringMapping(false); 
        }
    }, [learnedPatternSource, gridData, setGridData, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};
